     6→/**
     7→ * A representation of Python objects of type string.
     8→ */
     9→public class PyStringObj extends AIterablePyObj<PyCharObj> {
    10→
    11→    /**
    12→     * Constructor for a PySetObj; initializes its value to a list containing each
    13→     * character in the input String.
    14→     *
    15→     * @param value the sequence of characters representing the value of this PySetObj
    16→     */
    17→    public PyStringObj(String value) {
    18→        this.value = new ArrayList<>();
    19→        for (int idx = 0; idx < value.length(); idx++) {
    20→            this.value.add(new PyCharObj(value.charAt(idx)));
    21→        }
    22→    }
    23→
    24→    /**
    25→     * Constructor for a PySetObj; initializes its value to the input.
    26→     *
    27→     * @param value the value of this PySetObj
    28→     */
    29→    public PyStringObj(List<PyCharObj> value) {
    30→        this.value = value;
    31→    }
    32→
    33→    /**
    34→     * Builds and returns a string representation of this object that mirrors the Python
    35→     * string representation; uses single quotes for compatibility with command-line
    36→     * invocation of Python scripts.
    37→     *
    38→     * @return a string representation of this object
    39→     */
    40→    @Override
    41→    public String toString() {
    42→        // Concatenate all characters within this.value to get a single string
    43→        StringBuilder sb = new StringBuilder();
    44→        for (PyCharObj character : this.value) {
    45→            sb.append(character.getValue());
    46→        }
    47→
    48→        // Concatenate single quotes; this will automatically call sb.toString()
    49→        return "'" + sb + "'";
    50→    }
    51→
    52→    /**
    53→     * Compares this to the input object by value; a wrapper around the implementation
    54→     * in the superclass (APyObj) that first checks that obj is a PyStringObj.
    55→     *
    56→     * @param obj the object to compare against
    57→     * @return true if this is equivalent by value to obj; false otherwise
    58→     */
    59→    @Override
    60→    public boolean equals(Object obj) {
    61→        if (!(obj instanceof PyStringObj)) {
    62→            return false;
    63→        }
    64→        return super.equals(obj);
    65→    }
    66→}

