package main.rice.node;

import main.rice.obj.APyObj;
import java.util.List;
import java.util.Set;

/**
 * Abstract base class for all Python node types.
 * A node represents a domain of possible Python values and can generate them.
 *
 * @param <T> the type of Python object this node generates
 */
public abstract class APyNode<T extends APyObj> {

    /** The exhaustive domain (lengths for iterables, values for scalars). */
    protected List<Integer> exDomain;

    /** The random domain (lengths for iterables, values for scalars). */
    protected List<Integer> ranDomain;

    /**
     * Sets the exhaustive domain.
     *
     * @param exDomain the exhaustive domain
     */
    public void setExDomain(List<Integer> exDomain) {
        this.exDomain = exDomain;
    }

    /**
     * Returns the exhaustive domain.
     *
     * @return the exhaustive domain
     */
    public List<Integer> getExDomain() {
        return this.exDomain;
    }

    /**
     * Sets the random domain.
     *
     * @param ranDomain the random domain
     */
    public void setRanDomain(List<Integer> ranDomain) {
        this.ranDomain = ranDomain;
    }

    /**
     * Returns the random domain.
     *
     * @return the random domain
     */
    public List<Integer> getRanDomain() {
        return this.ranDomain;
    }

    /**
     * Returns the left child node, or null if none.
     *
     * @return the left child node
     */
    public APyNode<?> getLeftChild() {
        return null;
    }

    /**
     * Returns the right child node, or null if none.
     *
     * @return the right child node
     */
    public APyNode<?> getRightChild() {
        return null;
    }

    /**
     * Generates all exhaustive values based on the exhaustive domain.
     *
     * @return a set of all exhaustive values
     */
    public abstract Set<T> genExVals();

    /**
     * Generates a single random value based on the random domain.
     *
     * @return a random value
     */
    public abstract T genRandVal();
}

package main.rice.node;

import main.rice.obj.APyObj;

/**
 * Abstract base class for iterable Python node types (list, tuple, set).
 * Has a left child that generates the inner elements.
 *
 * @param <InnerType> the type of objects generated by the left child
 * @param <T>         the type of iterable object this node generates
 */
public abstract class AIterablePyNode<InnerType extends APyObj, T extends APyObj>
        extends APyNode<T> {

    /** The child node that generates the inner elements. */
    protected APyNode<InnerType> leftChild;

    /**
     * Constructor for an AIterablePyNode.
     *
     * @param leftChild the node that generates inner elements
     */
    public AIterablePyNode(APyNode<InnerType> leftChild) {
        this.leftChild = leftChild;
    }

    /**
     * Returns the left child node.
     *
     * @return the left child node
     */
    @Override
    public APyNode<?> getLeftChild() {
        return this.leftChild;
    }
}

package main.rice.node;

import main.rice.obj.PyIntObj;
import java.util.HashSet;
import java.util.Random;
import java.util.Set;

/**
 * A node that generates Python int values.
 * The exDomain and ranDomain contain the actual integer values (not lengths).
 */
public class PyIntNode extends APyNode<PyIntObj> {

    private static final Random random = new Random();

    /**
     * Generates all exhaustive integer values from the exDomain.
     *
     * @return a set of all PyIntObj values in the exhaustive domain
     */
    @Override
    public Set<PyIntObj> genExVals() {
        Set<PyIntObj> result = new HashSet<>();
        for (Integer val : this.exDomain) {
            result.add(new PyIntObj(val));
        }
        return result;
    }

    /**
     * Generates a single random integer value from the ranDomain.
     *
     * @return a random PyIntObj from the random domain
     */
    @Override
    public PyIntObj genRandVal() {
        int idx = random.nextInt(this.ranDomain.size());
        return new PyIntObj(this.ranDomain.get(idx));
    }
}

package main.rice.node;

import main.rice.obj.APyObj;
import main.rice.obj.PyListObj;
import java.util.*;

/**
 * A node that generates Python list values.
 * The exDomain and ranDomain specify the possible lengths.
 * The leftChild node generates the inner elements.
 *
 * @param <InnerType> the type of elements in the generated lists
 */
public class PyListNode<InnerType extends APyObj>
        extends AIterablePyNode<InnerType, PyListObj<InnerType>> {

    private static final Random random = new Random();

    /**
     * Constructor for a PyListNode.
     *
     * @param leftChild the node that generates inner elements
     */
    public PyListNode(APyNode<InnerType> leftChild) {
        super(leftChild);
    }

    /**
     * Generates all exhaustive list values. For each length in exDomain,
     * generates all lists of that length using elements from leftChild.genExVals()
     * (with repetition allowed).
     *
     * @return a set of all exhaustive PyListObj values
     */
    @Override
    public Set<PyListObj<InnerType>> genExVals() {
        Set<PyListObj<InnerType>> result = new HashSet<>();
        Set<InnerType> elements = leftChild.genExVals();

        for (Integer length : this.exDomain) {
            // Generate all lists of this length (with repetition)
            List<List<InnerType>> combos = genWithRepetition(new ArrayList<>(elements), length);
            for (List<InnerType> combo : combos) {
                result.add(new PyListObj<>(combo));
            }
        }
        return result;
    }

    /**
     * Generates a single random list. Picks a random length from ranDomain,
     * then for each position calls leftChild.genRandVal().
     *
     * @return a random PyListObj
     */
    @Override
    public PyListObj<InnerType> genRandVal() {
        int length = this.ranDomain.get(random.nextInt(this.ranDomain.size()));
        List<InnerType> elements = new ArrayList<>();
        for (int i = 0; i < length; i++) {
            elements.add(leftChild.genRandVal());
        }
        return new PyListObj<>(elements);
    }

    /**
     * Generates all lists of the given length from elements, with repetition allowed.
     */
    static <E> List<List<E>> genWithRepetition(List<E> elements, int length) {
        List<List<E>> combos = new ArrayList<>();
        combos.add(new ArrayList<>());

        for (int i = 0; i < length; i++) {
            List<List<E>> newCombos = new ArrayList<>();
            for (List<E> combo : combos) {
                for (E elem : elements) {
                    List<E> newCombo = new ArrayList<>(combo);
                    newCombo.add(elem);
                    newCombos.add(newCombo);
                }
            }
            combos = newCombos;
        }
        return combos;
    }
}

