public class PyTupleNode<InnerType extends APyObj>
        extends AIterablePyNode<InnerType, PyTupleObj<InnerType>> {

    private static final Random random = new Random();

    /**
     * Constructor for a PyTupleNode.
     *
     * @param leftChild the node that generates inner elements
     */
    public PyTupleNode(APyNode<InnerType> leftChild) {
        super(leftChild);
    }

    /**
     * Generates all exhaustive tuple values. For each length in exDomain,
     * generates all tuples of that length using elements from leftChild.genExVals()
     * (with repetition allowed).
     *
     * @return a set of all exhaustive PyTupleObj values
     */
    @Override
    public Set<PyTupleObj<InnerType>> genExVals() {
        Set<PyTupleObj<InnerType>> result = new HashSet<>();
        Set<InnerType> elements = leftChild.genExVals();

        for (Integer length : this.exDomain) {
            List<List<InnerType>> combos = PyListNode.genWithRepetition(new ArrayList<>(elements), length);
            for (List<InnerType> combo : combos) {
                result.add(new PyTupleObj<>(combo));
            }
        }
        return result;
    }

    /**
     * Generates a single random tuple. Picks a random length from ranDomain,
     * then for each position calls leftChild.genRandVal().
     *
     * @return a random PyTupleObj
     */
    @Override
    public PyTupleObj<InnerType> genRandVal() {
        int length = this.ranDomain.get(random.nextInt(this.ranDomain.size()));
        List<InnerType> elements = new ArrayList<>();
        for (int i = 0; i < length; i++) {
            elements.add(leftChild.genRandVal());
        }
