package main.rice.node;

import main.rice.obj.PyCharObj;
import main.rice.obj.PyStringObj;
import java.util.*;

/**
 * A node that generates Python string values.
 * Takes a string of allowed characters in its constructor.
 * Strings allow repeated characters (like lists).
 */
public class PyStringNode extends APyNode<PyStringObj> {

    private static final Random random = new Random();

    /** The set of allowed characters for generating strings. */
    private final List<PyCharObj> chars;

    /**
     * Constructor for a PyStringNode.
     *
     * @param chars a string whose characters are the allowed character domain
     */
    public PyStringNode(String chars) {
        this.chars = new ArrayList<>();
        for (int i = 0; i < chars.length(); i++) {
            this.chars.add(new PyCharObj(chars.charAt(i)));
        }
    }

    /**
     * Returns null since PyStringNode has no left child.
     *
     * @return null
     */
    @Override
    public APyNode<?> getLeftChild() {
        return null;
    }

    /**
     * Generates all exhaustive string values. For each length in exDomain,
     * generates all strings of that length using the character domain (with repetition).
     *
     * @return a set of all exhaustive PyStringObj values
     */
    @Override
    public Set<PyStringObj> genExVals() {
        Set<PyStringObj> result = new HashSet<>();
        for (Integer length : this.exDomain) {
            List<List<PyCharObj>> combos = PyListNode.genWithRepetition(this.chars, length);
            for (List<PyCharObj> combo : combos) {
                result.add(new PyStringObj(combo));
            }
        }
        return result;
    }

    /**
     * Generates a single random string. Picks a random length from ranDomain,
     * then picks random characters from the character domain.
     *
     * @return a random PyStringObj
     */
    @Override
    public PyStringObj genRandVal() {
        int length = this.ranDomain.get(random.nextInt(this.ranDomain.size()));
        List<PyCharObj> elements = new ArrayList<>();
        for (int i = 0; i < length; i++) {
            elements.add(this.chars.get(random.nextInt(this.chars.size())));
        }
        return new PyStringObj(elements);
    }
}

package main.rice.node;

import main.rice.obj.APyObj;
import main.rice.obj.PyDictObj;
import java.util.*;

/**
 * A node that generates Python dict values.
 * Has a left child (key generator) and right child (value generator).
 * Keys must be unique; values can repeat.
 *
 * @param <KeyType> the type of keys
 * @param <ValType> the type of values
 */
public class PyDictNode<KeyType extends APyObj, ValType extends APyObj>
        extends APyNode<PyDictObj<KeyType, ValType>> {

    private static final Random random = new Random();

    /** The child node that generates keys. */
    protected APyNode<KeyType> leftChild;

    /** The child node that generates values. */
    protected APyNode<ValType> rightChild;

    /**
     * Constructor for a PyDictNode.
     *
     * @param keyNode the node that generates keys
     * @param valNode the node that generates values
     */
    public PyDictNode(APyNode<KeyType> keyNode, APyNode<ValType> valNode) {
        this.leftChild = keyNode;
        this.rightChild = valNode;
    }

    /**
     * Returns the left child (key generator) node.
     *
     * @return the key node
     */
    @Override
    public APyNode<?> getLeftChild() {
        return this.leftChild;
    }

    /**
     * Returns the right child (value generator) node.
     *
     * @return the value node
     */
    @Override
    public APyNode<?> getRightChild() {
        return this.rightChild;
    }

    /**
     * Generates all exhaustive dict values. For each length in exDomain,
     * generates all C(|keys|, k) key combinations, and for each, all value
     * assignments (|vals|^k combinations).
     *
     * @return a set of all exhaustive PyDictObj values
     */
    @Override
    public Set<PyDictObj<KeyType, ValType>> genExVals() {
        Set<PyDictObj<KeyType, ValType>> result = new HashSet<>();
        List<KeyType> keyElems = new ArrayList<>(leftChild.genExVals());
        List<ValType> valElems = new ArrayList<>(rightChild.genExVals());

        for (Integer length : this.exDomain) {
            // Generate all k-combinations of keys (no duplicates)
            List<List<KeyType>> keyCombos = PySetNode.genCombinations(keyElems, length);

            for (List<KeyType> keyCombo : keyCombos) {
                // For this key combination, generate all value assignments
                List<List<ValType>> valAssignments =
                        PyListNode.genWithRepetition(valElems, length);

                for (List<ValType> valAssignment : valAssignments) {
                    Map<KeyType, ValType> map = new LinkedHashMap<>();
                    for (int i = 0; i < keyCombo.size(); i++) {
                        map.put(keyCombo.get(i), valAssignment.get(i));
                    }
                    result.add(new PyDictObj<>(map));
                }
            }
        }
        return result;
    }

    /**
     * Generates a single random dict. Picks a random size from ranDomain,
     * then picks distinct keys via leftChild.genRandVal() and values via
     * rightChild.genRandVal().
     *
     * @return a random PyDictObj
     */
    @Override
    public PyDictObj<KeyType, ValType> genRandVal() {
        int size = this.ranDomain.get(random.nextInt(this.ranDomain.size()));
        Map<KeyType, ValType> map = new LinkedHashMap<>();

        // Collect distinct keys
        Set<KeyType> keys = new LinkedHashSet<>();
        while (keys.size() < size) {
            keys.add(leftChild.genRandVal());
        }

        // Assign random value to each key
        for (KeyType key : keys) {
            map.put(key, rightChild.genRandVal());
        }
        return new PyDictObj<>(map);
    }
}

